const input = $input.first().json;
const action = input.action || '';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY };

const creds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.asana&cred_key=eq.asana_pat&select=cred_value',
  headers: pgHeaders
});
if (!creds || !creds[0] || !creds[0].cred_value) {
  return [{ json: { error: 'Asana PAT not configured. Use add_credential to set it up.' } }];
}
const pat = creds[0].cred_value;
const API = 'https://app.asana.com/api/1.0';
const authHeaders = { 'Authorization': 'Bearer ' + pat, 'Accept': 'application/json' };

function fmtDate(iso) {
  if (!iso) return '';
  return iso.substring(0, 10);
}

function truncate(text, max) {
  max = max || 5000;
  if (text.length > max) return text.substring(0, max) + '\n\n... (truncated, ' + text.length + ' chars total)';
  return text;
}

// === list_workspaces ===
if (action === 'list_workspaces') {
  try {
    const r = await helpers.httpRequest({ method: 'GET', url: API + '/workspaces?opt_fields=name,is_organization', headers: authHeaders });
    const items = r.data || [];
    if (items.length === 0) return [{ json: { result: 'No workspaces found.' } }];
    let out = 'Workspaces (' + items.length + '):\n';
    for (const w of items) {
      out += '  ' + w.name + ' (gid: ' + w.gid + (w.is_organization ? ', organization' : '') + ')\n';
    }
    return [{ json: { result: out } }];
  } catch (err) {
    return [{ json: { error: 'Asana list_workspaces failed: ' + err.message } }];
  }

// === list_projects ===
} else if (action === 'list_projects') {
  const workspace = input.workspace;
  if (!workspace) return [{ json: { error: 'Parameter "workspace" is required (workspace gid). Use list_workspaces first.' } }];
  const limit = Math.min(parseInt(input.limit) || 20, 100);
  const archived = input.archived === 'true' ? 'true' : 'false';
  try {
    const url = API + '/projects?workspace=' + encodeURIComponent(workspace) + '&archived=' + archived + '&limit=' + limit + '&opt_fields=name,archived,created_at,owner.name,current_status.title';
    const r = await helpers.httpRequest({ method: 'GET', url, headers: authHeaders });
    const items = r.data || [];
    if (items.length === 0) return [{ json: { result: 'No projects in workspace.' } }];
    let out = 'Projects (' + items.length + '):\n';
    for (const p of items) {
      out += '  ' + p.name + ' (gid: ' + p.gid + ')';
      if (p.archived) out += ' [ARCHIVED]';
      if (p.owner && p.owner.name) out += ' - owner: ' + p.owner.name;
      out += '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) {
    return [{ json: { error: 'Asana list_projects failed: ' + err.message } }];
  }

// === get_project ===
} else if (action === 'get_project') {
  const project = input.project;
  if (!project) return [{ json: { error: 'Parameter "project" is required (project gid).' } }];
  try {
    const r = await helpers.httpRequest({ method: 'GET', url: API + '/projects/' + encodeURIComponent(project) + '?opt_fields=name,notes,archived,created_at,modified_at,owner.name,current_status.title,current_status.text,due_date,start_on,members.name,permalink_url', headers: authHeaders });
    const p = r.data;
    if (!p) return [{ json: { error: 'Project not found.' } }];
    let out = '**' + p.name + '** (gid: ' + p.gid + ')\n';
    if (p.archived) out += 'Status: ARCHIVED\n';
    if (p.owner && p.owner.name) out += 'Owner: ' + p.owner.name + '\n';
    if (p.due_date) out += 'Due: ' + p.due_date + '\n';
    if (p.start_on) out += 'Start: ' + p.start_on + '\n';
    if (p.current_status && p.current_status.title) out += 'Current status: ' + p.current_status.title + (p.current_status.text ? ' — ' + p.current_status.text : '') + '\n';
    if (p.members && p.members.length) out += 'Members: ' + p.members.map(m => m.name).join(', ') + '\n';
    if (p.notes) out += '\nNotes:\n' + p.notes + '\n';
    if (p.permalink_url) out += '\n' + p.permalink_url + '\n';
    return [{ json: { result: truncate(out) } }];
  } catch (err) {
    return [{ json: { error: 'Asana get_project failed: ' + err.message } }];
  }

// === list_sections ===
} else if (action === 'list_sections') {
  const project = input.project;
  if (!project) return [{ json: { error: 'Parameter "project" is required (project gid).' } }];
  try {
    const r = await helpers.httpRequest({ method: 'GET', url: API + '/projects/' + encodeURIComponent(project) + '/sections?opt_fields=name,created_at', headers: authHeaders });
    const items = r.data || [];
    if (items.length === 0) return [{ json: { result: 'No sections in project.' } }];
    let out = 'Sections (' + items.length + '):\n';
    for (const s of items) out += '  ' + s.name + ' (gid: ' + s.gid + ')\n';
    return [{ json: { result: out } }];
  } catch (err) {
    return [{ json: { error: 'Asana list_sections failed: ' + err.message } }];
  }

// === list_tasks ===
} else if (action === 'list_tasks') {
  const project = input.project;
  const assignee = input.assignee;
  const section = input.section;
  const workspace = input.workspace;
  const limit = Math.min(parseInt(input.limit) || 20, 100);
  const completedSince = input.completed_since;

  const params = ['limit=' + limit, 'opt_fields=name,assignee.name,due_on,completed,completed_at,notes'];
  if (project) params.push('project=' + encodeURIComponent(project));
  else if (section) params.push('section=' + encodeURIComponent(section));
  else if (assignee) {
    if (!workspace) return [{ json: { error: 'When filtering by assignee, parameter "workspace" is also required. Use list_workspaces first.' } }];
    params.push('assignee=' + encodeURIComponent(assignee));
    params.push('workspace=' + encodeURIComponent(workspace));
  } else {
    return [{ json: { error: 'At least one filter is required: project, section, or assignee (with workspace).' } }];
  }
  if (completedSince) params.push('completed_since=' + encodeURIComponent(completedSince));

  try {
    const r = await helpers.httpRequest({ method: 'GET', url: API + '/tasks?' + params.join('&'), headers: authHeaders });
    const items = r.data || [];
    if (items.length === 0) return [{ json: { result: 'No tasks matched.' } }];
    let out = 'Tasks (' + items.length + '):\n';
    for (const t of items) {
      const mark = t.completed ? '[x]' : '[ ]';
      out += mark + ' ' + t.name + ' (gid: ' + t.gid + ')';
      if (t.assignee && t.assignee.name) out += ' @' + t.assignee.name;
      if (t.due_on) out += ' due:' + t.due_on;
      out += '\n';
    }
    if (r.next_page && r.next_page.offset) out += '\n(more results available — increase limit or request next page)\n';
    return [{ json: { result: truncate(out) } }];
  } catch (err) {
    return [{ json: { error: 'Asana list_tasks failed: ' + err.message } }];
  }

// === get_task ===
} else if (action === 'get_task') {
  const task = input.task;
  if (!task) return [{ json: { error: 'Parameter "task" is required (task gid).' } }];
  try {
    const r = await helpers.httpRequest({ method: 'GET', url: API + '/tasks/' + encodeURIComponent(task) + '?opt_fields=name,notes,assignee.name,due_on,due_at,start_on,completed,completed_at,projects.name,num_subtasks,tags.name,permalink_url,created_at,modified_at,parent.name', headers: authHeaders });
    const t = r.data;
    if (!t) return [{ json: { error: 'Task not found.' } }];
    let out = (t.completed ? '[x] ' : '[ ] ') + '**' + t.name + '** (gid: ' + t.gid + ')\n';
    if (t.assignee && t.assignee.name) out += 'Assignee: ' + t.assignee.name + '\n';
    if (t.due_on) out += 'Due: ' + t.due_on + (t.due_at ? ' (' + t.due_at + ')' : '') + '\n';
    if (t.start_on) out += 'Start: ' + t.start_on + '\n';
    if (t.completed_at) out += 'Completed: ' + fmtDate(t.completed_at) + '\n';
    if (t.projects && t.projects.length) out += 'Projects: ' + t.projects.map(p => p.name).join(', ') + '\n';
    if (t.tags && t.tags.length) out += 'Tags: ' + t.tags.map(x => x.name).join(', ') + '\n';
    if (t.parent && t.parent.name) out += 'Parent task: ' + t.parent.name + '\n';
    if (t.num_subtasks) out += 'Subtasks: ' + t.num_subtasks + '\n';
    if (t.notes) out += '\nNotes:\n' + t.notes + '\n';
    if (t.permalink_url) out += '\n' + t.permalink_url + '\n';
    return [{ json: { result: truncate(out) } }];
  } catch (err) {
    return [{ json: { error: 'Asana get_task failed: ' + err.message } }];
  }

// === create_task ===
} else if (action === 'create_task') {
  const name = input.name;
  if (!name) return [{ json: { error: 'Parameter "name" is required.' } }];
  const workspace = input.workspace;
  const project = input.project;
  if (!workspace && !project) return [{ json: { error: 'Either "workspace" or "project" is required to know where to create the task.' } }];
  const body = { data: { name } };
  if (workspace) body.data.workspace = workspace;
  if (project) body.data.projects = [project];
  if (input.notes) body.data.notes = input.notes;
  if (input.assignee) body.data.assignee = input.assignee;
  if (input.due_on) body.data.due_on = input.due_on;
  try {
    const r = await helpers.httpRequest({ method: 'POST', url: API + '/tasks?opt_fields=name,permalink_url,gid', headers: { ...authHeaders, 'Content-Type': 'application/json' }, body: JSON.stringify(body) });
    const t = r.data;
    let out = 'Task created: ' + t.name + ' (gid: ' + t.gid + ')';
    if (t.permalink_url) out += '\n' + t.permalink_url;
    return [{ json: { result: out } }];
  } catch (err) {
    return [{ json: { error: 'Asana create_task failed: ' + err.message } }];
  }

// === update_task ===
} else if (action === 'update_task') {
  const task = input.task;
  if (!task) return [{ json: { error: 'Parameter "task" is required (task gid).' } }];
  const body = { data: {} };
  if (input.name) body.data.name = input.name;
  if (input.notes) body.data.notes = input.notes;
  if (input.assignee) body.data.assignee = input.assignee;
  if (input.due_on) body.data.due_on = input.due_on;
  if (Object.keys(body.data).length === 0) return [{ json: { error: 'Provide at least one field to update: name, notes, assignee, due_on.' } }];
  try {
    const r = await helpers.httpRequest({ method: 'PUT', url: API + '/tasks/' + encodeURIComponent(task) + '?opt_fields=name,permalink_url,gid', headers: { ...authHeaders, 'Content-Type': 'application/json' }, body: JSON.stringify(body) });
    const t = r.data;
    let out = 'Task updated: ' + t.name + ' (gid: ' + t.gid + ')';
    if (t.permalink_url) out += '\n' + t.permalink_url;
    return [{ json: { result: out } }];
  } catch (err) {
    return [{ json: { error: 'Asana update_task failed: ' + err.message } }];
  }

// === complete_task ===
} else if (action === 'complete_task') {
  const task = input.task;
  if (!task) return [{ json: { error: 'Parameter "task" is required (task gid).' } }];
  try {
    const r = await helpers.httpRequest({ method: 'PUT', url: API + '/tasks/' + encodeURIComponent(task) + '?opt_fields=name,completed,gid', headers: { ...authHeaders, 'Content-Type': 'application/json' }, body: JSON.stringify({ data: { completed: true } }) });
    const t = r.data;
    return [{ json: { result: 'Task completed: ' + t.name + ' (gid: ' + t.gid + ')' } }];
  } catch (err) {
    return [{ json: { error: 'Asana complete_task failed: ' + err.message } }];
  }

// === add_comment_to_task ===
} else if (action === 'add_comment_to_task') {
  const task = input.task;
  const text = input.text;
  if (!task) return [{ json: { error: 'Parameter "task" is required (task gid).' } }];
  if (!text) return [{ json: { error: 'Parameter "text" is required (comment body).' } }];
  try {
    const r = await helpers.httpRequest({ method: 'POST', url: API + '/tasks/' + encodeURIComponent(task) + '/stories?opt_fields=gid,created_at,created_by.name', headers: { ...authHeaders, 'Content-Type': 'application/json' }, body: JSON.stringify({ data: { text } }) });
    const s = r.data;
    return [{ json: { result: 'Comment added (gid: ' + s.gid + ')' + (s.created_by && s.created_by.name ? ' by ' + s.created_by.name : '') } }];
  } catch (err) {
    return [{ json: { error: 'Asana add_comment_to_task failed: ' + err.message } }];
  }

// === list_comments ===
} else if (action === 'list_comments') {
  const task = input.task;
  if (!task) return [{ json: { error: 'Parameter "task" is required (task gid).' } }];
  const includeSystem = input.include_system === 'true';
  try {
    const r = await helpers.httpRequest({ method: 'GET', url: API + '/tasks/' + encodeURIComponent(task) + '/stories?opt_fields=text,created_at,created_by.name,type', headers: authHeaders });
    const items = (r.data || []).filter(s => includeSystem || s.type === 'comment');
    if (items.length === 0) return [{ json: { result: 'No comments on task.' + (includeSystem ? '' : ' Set include_system=true to see system events.') } }];
    let out = 'Comments (' + items.length + '):\n\n';
    for (const s of items) {
      const when = s.created_at ? s.created_at.substring(0, 10) : '';
      const who = s.created_by && s.created_by.name ? s.created_by.name : 'unknown';
      const tag = s.type === 'comment' ? '' : '[' + s.type + '] ';
      out += tag + who + ' (' + when + '):\n  ' + (s.text || '') + '\n\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) {
    return [{ json: { error: 'Asana list_comments failed: ' + err.message } }];
  }

// === list_subtasks ===
} else if (action === 'list_subtasks') {
  const task = input.task;
  if (!task) return [{ json: { error: 'Parameter "task" is required (parent task gid).' } }];
  const limit = Math.min(parseInt(input.limit) || 50, 100);
  try {
    const r = await helpers.httpRequest({ method: 'GET', url: API + '/tasks/' + encodeURIComponent(task) + '/subtasks?limit=' + limit + '&opt_fields=name,completed,due_on,assignee.name', headers: authHeaders });
    const items = r.data || [];
    if (items.length === 0) return [{ json: { result: 'No subtasks.' } }];
    let out = 'Subtasks (' + items.length + '):\n';
    for (const t of items) {
      const mark = t.completed ? '[x]' : '[ ]';
      out += mark + ' ' + t.name + ' (gid: ' + t.gid + ')';
      if (t.assignee && t.assignee.name) out += ' @' + t.assignee.name;
      if (t.due_on) out += ' due:' + t.due_on;
      out += '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) {
    return [{ json: { error: 'Asana list_subtasks failed: ' + err.message } }];
  }

// === create_subtask ===
} else if (action === 'create_subtask') {
  const task = input.task;
  const name = input.name;
  if (!task) return [{ json: { error: 'Parameter "task" is required (parent task gid).' } }];
  if (!name) return [{ json: { error: 'Parameter "name" is required.' } }];
  const body = { data: { name } };
  if (input.notes) body.data.notes = input.notes;
  if (input.assignee) body.data.assignee = input.assignee;
  if (input.due_on) body.data.due_on = input.due_on;
  try {
    const r = await helpers.httpRequest({ method: 'POST', url: API + '/tasks/' + encodeURIComponent(task) + '/subtasks?opt_fields=gid,name,permalink_url', headers: { ...authHeaders, 'Content-Type': 'application/json' }, body: JSON.stringify(body) });
    const t = r.data;
    let out = 'Subtask created: ' + t.name + ' (gid: ' + t.gid + ')';
    if (t.permalink_url) out += '\n' + t.permalink_url;
    return [{ json: { result: out } }];
  } catch (err) {
    return [{ json: { error: 'Asana create_subtask failed: ' + err.message } }];
  }

// === move_task_to_section ===
} else if (action === 'move_task_to_section') {
  const task = input.task;
  const section = input.section;
  if (!task) return [{ json: { error: 'Parameter "task" is required (task gid).' } }];
  if (!section) return [{ json: { error: 'Parameter "section" is required (target section gid). Use list_sections to find section gids.' } }];
  try {
    await helpers.httpRequest({ method: 'POST', url: API + '/sections/' + encodeURIComponent(section) + '/addTask', headers: { ...authHeaders, 'Content-Type': 'application/json' }, body: JSON.stringify({ data: { task } }) });
    return [{ json: { result: 'Task ' + task + ' moved to section ' + section + '.' } }];
  } catch (err) {
    return [{ json: { error: 'Asana move_task_to_section failed: ' + err.message } }];
  }

// === search_users ===
} else if (action === 'search_users') {
  const workspace = input.workspace;
  const query = input.query;
  if (!workspace) return [{ json: { error: 'Parameter "workspace" is required (workspace gid). Use list_workspaces first.' } }];
  if (!query) return [{ json: { error: 'Parameter "query" is required (name or email fragment).' } }];
  const count = Math.min(parseInt(input.count) || 10, 100);
  try {
    const url = API + '/workspaces/' + encodeURIComponent(workspace) + '/typeahead?resource_type=user&query=' + encodeURIComponent(query) + '&count=' + count + '&opt_fields=name,email';
    const r = await helpers.httpRequest({ method: 'GET', url, headers: authHeaders });
    const items = r.data || [];
    if (items.length === 0) return [{ json: { result: 'No users matched "' + query + '" in this workspace.' } }];
    let out = 'Users (' + items.length + '):\n';
    for (const u of items) {
      out += '  ' + u.name + ' (gid: ' + u.gid + (u.email ? ', ' + u.email : '') + ')\n';
    }
    return [{ json: { result: out } }];
  } catch (err) {
    return [{ json: { error: 'Asana search_users failed: ' + err.message } }];
  }

// === search_tasks ===
} else if (action === 'search_tasks') {
  const workspace = input.workspace;
  const query = input.query;
  if (!workspace) return [{ json: { error: 'Parameter "workspace" is required (workspace gid).' } }];
  if (!query) return [{ json: { error: 'Parameter "query" is required (task name fragment).' } }];
  const count = Math.min(parseInt(input.count) || 10, 100);
  try {
    const url = API + '/workspaces/' + encodeURIComponent(workspace) + '/typeahead?resource_type=task&query=' + encodeURIComponent(query) + '&count=' + count + '&opt_fields=name,completed';
    const r = await helpers.httpRequest({ method: 'GET', url, headers: authHeaders });
    const items = r.data || [];
    if (items.length === 0) return [{ json: { result: 'No tasks matched "' + query + '".' } }];
    let out = 'Tasks (' + items.length + '):\n';
    for (const t of items) {
      const mark = t.completed ? '[x]' : '[ ]';
      out += mark + ' ' + t.name + ' (gid: ' + t.gid + ')\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) {
    return [{ json: { error: 'Asana search_tasks failed: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: "' + action + '". Available: list_workspaces, list_projects, get_project, list_sections, list_tasks, get_task, create_task, update_task, complete_task, add_comment_to_task, list_comments, list_subtasks, create_subtask, move_task_to_section, search_users, search_tasks.' } }];
}
